import{_ as o,o as s,c as t,ak as a}from"./chunks/framework.tZEZYUNo.js";const g=JSON.parse('{"title":"Contributing Docs","description":"","frontmatter":{},"headers":[],"relativePath":"contributing.md","filePath":"contributing.md"}'),d={name:"contributing.md"};function i(c,e,n,l,r,p){return s(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="contributing-docs" tabindex="-1">Contributing Docs <a class="header-anchor" href="#contributing-docs" aria-label="Permalink to “Contributing Docs”">​</a></h1><p>This page explains where to put docs and what your changes do in the site UI.</p><p>Run docs commands from the monorepo root (the folder that contains <code>package.json</code>).</p><h2 id="where-to-write-docs" tabindex="-1">Where to write docs <a class="header-anchor" href="#where-to-write-docs" aria-label="Permalink to “Where to write docs”">​</a></h2><p>Keep docs beside the code they describe:</p><ul><li>Plugin docs: <code>plugins/&lt;plugin-slug&gt;/docs/</code></li><li>Theme docs: <code>themes/&lt;theme-slug&gt;/docs/</code></li></ul><p>Minimum per package:</p><ul><li><code>index.md</code> (required)</li><li>Optional extra pages such as <code>usage.md</code>, <code>faq.md</code>, <code>api.md</code></li></ul><p>Example:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>plugins/example-plugin/</span></span>
<span class="line"><span>  docs/</span></span>
<span class="line"><span>    index.md</span></span>
<span class="line"><span>    usage.md</span></span></code></pre></div><h2 id="what-changes-appear-where" tabindex="-1">What changes appear where <a class="header-anchor" href="#what-changes-appear-where" aria-label="Permalink to “What changes appear where”">​</a></h2><ul><li>Add <code>docs/index.md</code> in a plugin or theme -&gt; package appears in the left sidebar under <code>Plugins</code> or <code>Themes</code>.</li><li>Add another markdown file (example <code>usage.md</code>) -&gt; creates another page route for that package.</li><li>Add a heading like <code>## Setup</code> in a page -&gt; appears in the right-side &quot;On this page&quot; links as <code>Setup</code>.</li><li>Rename a heading -&gt; right-side &quot;On this page&quot; link text also changes.</li><li>Remove a heading -&gt; its right-side link disappears.</li></ul><p>Note: only headings in page content (<code>##</code>, <code>###</code>, etc.) create &quot;On this page&quot; links. A normal bold line is not a heading.</p><h2 id="do-not-edit-generated-docs" tabindex="-1">Do not edit generated docs <a class="header-anchor" href="#do-not-edit-generated-docs" aria-label="Permalink to “Do not edit generated docs”">​</a></h2><p><code>docs/content/</code> is generated output. Do not edit files there directly because they are replaced during sync.</p><h2 id="how-docs-sync-works" tabindex="-1">How <code>docs:sync</code> works <a class="header-anchor" href="#how-docs-sync-works" aria-label="Permalink to “How docs:sync works”">​</a></h2><p><code>pnpm docs:sync</code> runs <code>tools/sync-docs.mjs</code>.</p><p>It:</p><ul><li>deletes <code>docs/content/</code> (generated output)</li><li>recreates <code>docs/content/</code></li><li>copies package docs from: <ul><li><code>plugins/&lt;slug&gt;/docs/**</code> -&gt; <code>docs/content/plugins/&lt;slug&gt;/</code></li><li><code>themes/&lt;slug&gt;/docs/**</code> -&gt; <code>docs/content/themes/&lt;slug&gt;/</code></li></ul></li></ul><p>Why this exists:</p><ul><li>The VitePress-based site builds from <code>docs/</code></li><li>package docs are owned inside package folders</li><li>sync combines both into one build input</li></ul><h2 id="safe-workflow-step-by-step" tabindex="-1">Safe workflow (step-by-step) <a class="header-anchor" href="#safe-workflow-step-by-step" aria-label="Permalink to “Safe workflow (step-by-step)”">​</a></h2><ol><li>Edit docs only in <code>plugins/.../docs</code> or <code>themes/.../docs</code></li><li>Start docs: <code>pnpm docs:dev</code> (runs sync once on start, then re-runs sync when <code>plugins/**/docs/**</code>, <code>themes/**/docs/**</code>, or <code>tools/sync-docs.mjs</code> changes)</li><li>Check your package in the left sidebar</li><li>Open your page and check right-side &quot;On this page&quot; links</li><li>Commit source docs only (not generated <code>docs/content</code>)</li></ol>`,23)])])}const u=o(d,[["render",i]]);export{g as __pageData,u as default};
